        [Test]
        [Ignore(&#34;Only verifying that the sample builds&#34;)]
        public async Task ListUsageDetails()
        {
            #region Snippet:ListConsumptionUsageDetails
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = &#34;&#34;;
            ResourceIdentifier scope = new ResourceIdentifier($&#34;/subscriptions/{subscriptionId}&#34;);

            await foreach (ConsumptionUsageDetail usageDetail in client.GetConsumptionUsageDetailsAsync(scope))
            {
                Console.WriteLine($&#34;Resource: {usageDetail.Id}, Cost: {usageDetail.PretaxCost}&#34;);
            }
            #endregion
        }
